/// Lua 值类型枚举。
///
/// 对应 Lua 源码中的 LUA_TNONE / LUA_TNIL / LUA_TBOOLEAN 等。
/// 在 shim 层中，所有返回/接收 Lua 类型的 API 均使用此枚举。
enum lua_shim_type {
  LUA_SHIM_TNONE(-1),
  LUA_SHIM_TNIL(0),
  LUA_SHIM_TBOOLEAN(1),
  LUA_SHIM_TLIGHTUSERDATA(2),
  LUA_SHIM_TNUMBER(3),
  LUA_SHIM_TSTRING(4),
  LUA_SHIM_TTABLE(5),
  LUA_SHIM_TFUNCTION(6),
  LUA_SHIM_TUSERDATA(7),
  LUA_SHIM_TTHREAD(8);

  final int value;
  const lua_shim_type(this.value);

  static lua_shim_type fromValue(int value) => switch (value) {
    -1 => LUA_SHIM_TNONE,
    0 => LUA_SHIM_TNIL,
    1 => LUA_SHIM_TBOOLEAN,
    2 => LUA_SHIM_TLIGHTUSERDATA,
    3 => LUA_SHIM_TNUMBER,
    4 => LUA_SHIM_TSTRING,
    5 => LUA_SHIM_TTABLE,
    6 => LUA_SHIM_TFUNCTION,
    7 => LUA_SHIM_TUSERDATA,
    8 => LUA_SHIM_TTHREAD,
    _ => throw ArgumentError('Unknown value for lua_shim_type: $value'),
  };
}

/// Lua 线程/调用状态枚举。
///
/// 对应 LUA_OK / LUA_YIELD / LUA_ERRRUN 等。
/// 所有返回状态码的 API（pcall、resume、loadstring 等）均使用此枚举。
enum lua_shim_status {
  LUA_SHIM_OK(0),
  LUA_SHIM_YIELD(1),
  LUA_SHIM_ERRRUN(2),
  LUA_SHIM_ERRSYNTAX(3),
  LUA_SHIM_ERRMEM(4),
  LUA_SHIM_ERRGCMM(5),
  LUA_SHIM_ERRERR(6);

  final int value;
  const lua_shim_status(this.value);

  static lua_shim_status fromValue(int value) => switch (value) {
    0 => LUA_SHIM_OK,
    1 => LUA_SHIM_YIELD,
    2 => LUA_SHIM_ERRRUN,
    3 => LUA_SHIM_ERRSYNTAX,
    4 => LUA_SHIM_ERRMEM,
    5 => LUA_SHIM_ERRGCMM,
    6 => LUA_SHIM_ERRERR,
    _ => throw ArgumentError('Unknown value for lua_shim_status: $value'),
  };
}

